package com.example.saml.saml;

import org.opensaml.saml.common.SAMLVersion;
import org.opensaml.saml.saml2.core.*;
import org.opensaml.security.SecurityException;
import org.opensaml.xmlsec.signature.Signature;
import org.opensaml.xmlsec.signature.support.SignatureConstants;
import org.opensaml.xmlsec.signature.support.Signer;

import java.time.Clock;
import java.time.Instant;
import java.util.UUID;

public class SamlRequestBuilder {

    private final SamlObjectSupport support;
    private final SamlSignatureService sig;
    private final Clock clock;
    private final String spEntityId;
    private final String acsUrl;
    private final String idpSsoUrl;
    private final String idpEntityId;
    private final String nameIdFormat;

    public SamlRequestBuilder(SamlObjectSupport support,
                              SamlSignatureService sig,
                              Clock clock,
                              String spEntityId,
                              String acsUrl,
                              String idpSsoUrl,
                              String idpEntityId,
                              String nameIdFormat) {
        this.support = support;
        this.sig = sig;
        this.clock = clock;
        this.spEntityId = spEntityId;
        this.acsUrl = acsUrl;
        this.idpSsoUrl = idpSsoUrl;
        this.idpEntityId = idpEntityId;
        this.nameIdFormat = nameIdFormat;
    }

    public String buildAuthnRequestXml() {
        AuthnRequest req = support.build(AuthnRequest.class);
        req.setID("_" + UUID.randomUUID());
        req.setVersion(SAMLVersion.VERSION_20);
        req.setIssueInstant(Instant.now(clock));
        req.setDestination(idpSsoUrl);
        req.setAssertionConsumerServiceURL(acsUrl);
        req.setProtocolBinding(SamlConstants.BINDING_HTTP_POST);

        Issuer issuer = support.build(Issuer.class);
        issuer.setValue(spEntityId);
        req.setIssuer(issuer);

        NameIDPolicy nameIDPolicy = support.build(NameIDPolicy.class);
        nameIDPolicy.setFormat(nameIdFormat);
        nameIDPolicy.setAllowCreate(true);
        req.setNameIDPolicy(nameIDPolicy);

        RequestedAuthnContext rac = support.build(RequestedAuthnContext.class);
        rac.setComparison(AuthnContextComparisonTypeEnumeration.EXACT);
        AuthnContextClassRef ref = support.build(AuthnContextClassRef.class);
        ref.setURI(AuthnContext.PPT_AUTHN_CTX);
        rac.getAuthnContextClassRefs().add(ref);
        req.setRequestedAuthnContext(rac);

        Signature signature = sig.buildSignature(SignatureConstants.ALGO_ID_SIGNATURE_RSA_SHA256);
        req.setSignature(signature);

        String xml = support.toXml(req);

        try {
            Signer.signObject(signature);
        } catch (org.opensaml.xmlsec.signature.support.SignatureException e) {
            throw new RuntimeException(e);
        }

        return support.toXml(req);
    }
}

package com.example.saml.saml;

import org.opensaml.core.xml.XMLObject;
import org.opensaml.saml.saml2.core.*;
import org.opensaml.security.credential.Credential;
import org.opensaml.xmlsec.signature.Signature;
import org.opensaml.xmlsec.signature.support.SignatureValidator;
import org.opensaml.xmlsec.signature.support.SAMLSignatureProfileValidator;

import java.time.Clock;
import java.time.Instant;
import java.util.*;

public class SamlResponseValidator {

    public record AuthResult(String subject, String sessionIndex, Map<String, List<String>> attributes) {}

    private final SamlObjectSupport support;
    private final SamlSignatureService sig;
    private final Clock clock;
    private final String spEntityId;
    private final String idpEntityId;
    private final String acsUrl;
    private final long skewSeconds;
    private final long maxAgeSeconds;
    private final Credential idpCredential;

    public SamlResponseValidator(SamlObjectSupport support,
                                 SamlSignatureService sig,
                                 Clock clock,
                                 String spEntityId,
                                 String idpEntityId,
                                 String acsUrl,
                                 long skewSeconds,
                                 long maxAgeSeconds,
                                 String idpCertificatePem) {
        this.support = support;
        this.sig = sig;
        this.clock = clock;
        this.spEntityId = spEntityId;
        this.idpEntityId = idpEntityId;
        this.acsUrl = acsUrl;
        this.skewSeconds = skewSeconds;
        this.maxAgeSeconds = maxAgeSeconds;
        this.idpCredential = sig.credentialFromIdpPem(idpCertificatePem);
    }

    public AuthResult validate(String samlResponseXml) throws Exception {
        XMLObject obj = support.fromXml(samlResponseXml);
        if (!(obj instanceof Response response)) {
            throw new IllegalArgumentException("Not a SAML Response");
        }

        if (response.getIssuer() == null || !idpEntityId.equals(response.getIssuer().getValue())) {
            throw new SecurityException("Invalid response issuer");
        }

        if (response.getDestination() != null && !acsUrl.equals(response.getDestination())) {
            throw new SecurityException("Invalid destination");
        }

        Instant now = Instant.now(clock);
        if (response.getIssueInstant() == null) throw new SecurityException("Missing issueInstant");
        if (Math.abs(now.getEpochSecond() - response.getIssueInstant().getEpochSecond()) > (maxAgeSeconds + skewSeconds)) {
            throw new SecurityException("Response too old");
        }

        boolean responseSigned = response.getSignature() != null;
        Assertion assertion = response.getAssertions() != null && !response.getAssertions().isEmpty() ? response.getAssertions().getFirst() : null;
        boolean assertionSigned = assertion != null && assertion.getSignature() != null;

        if (!responseSigned && !assertionSigned) {
            throw new SecurityException("Neither Response nor Assertion is signed");
        }

        if (responseSigned) validateSignature(response.getSignature());
        if (assertionSigned) validateSignature(assertion.getSignature());

        if (assertion == null) throw new SecurityException("Missing assertion");
        if (assertion.getIssuer() == null || !idpEntityId.equals(assertion.getIssuer().getValue())) {
            throw new SecurityException("Invalid assertion issuer");
        }

        validateConditions(assertion.getConditions(), now);

        Subject subject = assertion.getSubject();
        if (subject == null || subject.getNameID() == null) throw new SecurityException("Missing subject");
        String nameId = subject.getNameID().getValue();

        validateSubjectConfirmation(subject, now);

        String sessionIndex = null;
        if (assertion.getAuthnStatements() != null && !assertion.getAuthnStatements().isEmpty()) {
            sessionIndex = assertion.getAuthnStatements().getFirst().getSessionIndex();
        }

        Map<String, List<String>> attributes = extractAttributes(assertion);

        return new AuthResult(nameId, sessionIndex, attributes);
    }

    private void validateSignature(Signature signature) throws Exception {
        new SAMLSignatureProfileValidator().validate(signature);
        SignatureValidator.validate(signature, idpCredential);
    }

    private void validateConditions(Conditions conditions, Instant now) throws SecurityException {
        if (conditions == null) throw new SecurityException("Missing conditions");

        Instant notBefore = conditions.getNotBefore();
        Instant notOnOrAfter = conditions.getNotOnOrAfter();

        if (notBefore != null && now.isBefore(notBefore.minusSeconds(skewSeconds))) {
            throw new SecurityException("Assertion not yet valid");
        }
        if (notOnOrAfter != null && !now.isBefore(notOnOrAfter.plusSeconds(skewSeconds))) {
            throw new SecurityException("Assertion expired");
        }

        boolean audienceOk = false;
        if (conditions.getAudienceRestrictions() != null) {
            for (AudienceRestriction ar : conditions.getAudienceRestrictions()) {
                for (Audience aud : ar.getAudiences()) {
                    if (spEntityId.equals(aud.getURI())) {
                        audienceOk = true;
                        break;
                    }
                }
                if (audienceOk) break;
            }
        }
        if (!audienceOk) throw new SecurityException("Audience restriction failed");
    }

    private void validateSubjectConfirmation(Subject subject, Instant now) throws SecurityException {
        if (subject.getSubjectConfirmations() == null || subject.getSubjectConfirmations().isEmpty()) {
            throw new SecurityException("Missing subject confirmation");
        }
        boolean ok = false;
        for (SubjectConfirmation sc : subject.getSubjectConfirmations()) {
            if (!SubjectConfirmation.METHOD_BEARER.equals(sc.getMethod())) continue;
            SubjectConfirmationData data = sc.getSubjectConfirmationData();
            if (data == null) continue;
            if (data.getRecipient() != null && !acsUrl.equals(data.getRecipient())) continue;
            Instant noo = data.getNotOnOrAfter();
            if (noo != null && !now.isBefore(noo.plusSeconds(skewSeconds))) continue;
            ok = true;
            break;
        }
        if (!ok) throw new SecurityException("Subject confirmation failed");
    }

    private Map<String, List<String>> extractAttributes(Assertion assertion) {
        Map<String, List<String>> out = new LinkedHashMap<>();
        if (assertion.getAttributeStatements() == null) return out;
        for (AttributeStatement st : assertion.getAttributeStatements()) {
            for (Attribute a : st.getAttributes()) {
                String name = a.getName();
                List<String> vals = out.computeIfAbsent(name, k -> new ArrayList<>());
                if (a.getAttributeValues() != null) {
                    for (XMLObject v : a.getAttributeValues()) {
                        String text = v.getDOM() != null ? v.getDOM().getTextContent() : v.toString();
                        if (text != null) vals.add(text);
                    }
                }
            }
        }
        return out;
    }
}

